def _validate_url(url):
    """
    Validate that a URL belongs to an allowed internal domain.
    Prevents downloading from arbitrary or malicious sources.
    """
    from urllib.parse import urlparse

    parsed = urlparse(url)

    # Enforce HTTPS only
    if parsed.scheme != "https":
        raise ValueError(
            f"Only HTTPS URLs are allowed. Got scheme: '{parsed.scheme}' for URL: {url}"
        )

    # Check against allowed domains
    base_url = f"{parsed.scheme}://{parsed.hostname}"
    if base_url not in ALLOWED_RESOURCE_DOMAINS:
        raise ValueError(
            f"URL domain not in allowed list. Got: '{base_url}'. "
            f"Allowed domains: {ALLOWED_RESOURCE_DOMAINS}"
        )

    # Prevent path traversal in URL
    if ".." in parsed.path:
        raise ValueError(f"Path traversal detected in URL: {url}")

    return True


def _validate_filename(filename):
    """
    Validate that a filename is safe and doesn't contain path traversal.
    """
    # Prevent path traversal
    if ".." in filename or os.sep in filename or "/" in filename:
        raise ValueError(f"Invalid filename (path traversal attempt): {filename}")

    # Prevent hidden files or suspicious names
    if filename.startswith("."):
        raise ValueError(f"Hidden files not allowed: {filename}")

    # Only allow alphanumeric, hyphens, underscores, and dots
    import re
    if not re.match(r'^[a-zA-Z0-9_\-]+\.[a-zA-Z0-9]+$', filename):
        raise ValueError(f"Filename contains disallowed characters: {filename}")

    return True


def _validate_subdir(subdir):
    """
    Validate that a subdirectory name is safe.
    """
    if ".." in subdir or subdir.startswith("/") or subdir.startswith(os.sep):
        raise ValueError(f"Invalid subdirectory (path traversal attempt): {subdir}")

    import re
    if not re.match(r'^[a-zA-Z0-9_\-]+$', subdir):
        raise ValueError(f"Subdirectory contains disallowed characters: {subdir}")

    return True


def _verify_checksum(filepath, expected_sha256):
    """
    Verify the SHA-256 checksum of a downloaded file.
    Ensures file integrity and prevents tampering.
    """
    import hashlib

    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256_hash.update(chunk)

    actual_hash = sha256_hash.hexdigest()
    if actual_hash != expected_sha256:
        # Remove the file if checksum doesn't match
        os.remove(filepath)
        raise ValueError(
            f"Checksum verification failed for {filepath}. "
            f"Expected: {expected_sha256}, Got: {actual_hash}"
        )

    logger.info(f"Checksum verified for {filepath}")
    return True


