            if not real_target.startswith(real_config + os.sep):
                raise ValueError(
                    f"Target directory resolves outside config dir: {real_target}"
                )

            if os.path.exists(target_path):
                logger.info(
                    f"Resource '{resource['name']}' already exists. Skipping."
                )
                continue

            logger.info(f"Downloading resource '{resource['name']}' from {url}")

            # Download to a temporary file first
